    let addr = "[::1]:50051".parse()?;
    let matcher = MatcherService::new();

    println!("Matcher gRPC server listening on {}", addr);

    Server::builder()
        .add_service(MatchingServerServiceServer::new(matcher))
        .serve(addr)
